}

test compute_value_2_ada() {
  compute_value(2_000_000, 70_000_000, -8) == 1_400_000
}

test health_ratio_150pct() {
  // 1.5 ADA bloqueados (1_500_000 lovelaces), deuda de 700_000 micro-USD
  // valor_colateral = 1_500_000 * 70_000_000 / 100_000_000 = 1_050_000
  // ratio = 1_050_000 * 100 / 700_000 = 150
  health_ratio(1_500_000, 700_000, 70_000_000, -8) == 150
}

test health_ratio_200pct() {
  // 2 ADA (2_000_000 lovelaces), deuda de 700_000 micro-USD
  // valor_colateral = 2_000_000 * 70_000_000 / 100_000_000 = 1_400_000
  // ratio = 1_400_000 * 100 / 700_000 = 200
  health_ratio(2_000_000, 700_000, 70_000_000, -8) == 200
}

test health_ratio_exacto_100pct() {
  // 1 ADA (1_000_000 lovelaces), deuda de 700_000 micro-USD
  // valor_colateral = 700_000
  // ratio = 700_000 * 100 / 700_000 = 100
  health_ratio(1_000_000, 700_000, 70_000_000, -8) == 100
