use aiken/collection/list
use aiken/interval.{Finite, IntervalBound}
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type CollateralDatum {
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  minted_synth: Int,
  collateral_ratio: Int,
  max_age_ms: Int,
  owner: ByteArray,
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

fn health_ratio(
  ada_lovelaces: Int,
  minted_synth: Int,
  raw_price: Int,
  exponent: Int,
) -> Int {
  let collateral_usd = compute_value(ada_lovelaces, raw_price, exponent)
  collateral_usd * 100 / minted_synth
}

pub type CollateralAction {
  Withdraw
  Liquidate
}

validator collateral_floor {
  spend(
    datum_opt: Option<Data>,
    redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum_opt
    expect col_datum: CollateralDatum = raw_datum
    expect action: CollateralAction = redeemer
    let oracle =
      get_oracle_datum(
        col_datum.oracle_policy,
        col_datum.oracle_asset,
        self.reference_inputs,
      )
    // Verificación de frescura del oráculo
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let is_fresh = upper - oracle.timestamp < col_datum.max_age_ms
    // Encontrar el UTxO que se está gastando para obtener el valor de lovelace
    expect Some(spent_input) =
      list.find(self.inputs, fn(i) { i.output_reference == utxo })
    let locked_lovelace = assets.lovelace_of(spent_input.output.value)
    let current_health =
      health_ratio(
        locked_lovelace,
        col_datum.minted_synth,
        oracle.price,
        oracle.exponent,
      )
    when action is {
      Withdraw -> {
        // Solo el dueño puede retirar, precio debe ser fresco, y ratio >= colateral mínimo
        let signed =
          list.has(self.extra_signatories, col_datum.owner)
        is_fresh && signed && current_health >= col_datum.collateral_ratio
      }
      Liquidate -> {
        // Cualquiera puede liquidar si el ratio de salud está debajo del umbral
        is_fresh && current_health < col_datum.collateral_ratio
      }
    }
  }

  else(_) {
    fail
  }
}

