/// Check that a script credential is present in the transaction inputs
fn script_input_exists(
  inputs: List<Input>,
  script_hash: ByteArray,
) -> Bool {
  list.any(
    inputs,
    fn(inp) {
      when inp.output.address.payment_credential is {
        Script(sh) -> sh == script_hash
        _ -> False
      }
    },
  )
}

validator cdp_advanced(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  collateral_ratio: Int,
  liquidation_threshold: Int,
  max_age_ms: Int,
  cdp_script_hash: ByteArray,
  synth_asset_name: AssetName,
) {
  spend(
    datum_opt: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum_opt
    expect cdp: CdpDatum = raw_datum
    expect action: Action = redeemer
    let oracle =
      get_oracle_datum(oracle_policy, oracle_asset, self.reference_inputs)
    // Staleness check
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    expect upper - oracle.timestamp < max_age_ms
    when action is {
      Mint -> {
        let owner_signed =
          list.has(self.extra_signatories, cdp.owner)
        // Find continuing output back to this script
        expect Some(cont_output) =
          list.find(
            self.outputs,
            fn(o) {
              when o.address.payment_credential is {
                Script(sh) -> sh == cdp_script_hash
                _ -> False
              }
            },
          )
        // Check new datum on continuing output
        expect InlineDatum(raw_new) = cont_output.datum
        expect new_cdp: CdpDatum = raw_new
        // Validate the new position is sufficiently collateralized
        let new_collateral_value =
          compute_value(
            new_cdp.ada_locked,
            oracle.price,
            oracle.exponent,
          )
        let required_collateral =
          new_cdp.synth_minted * collateral_ratio / 100
        // New synth minted must exceed old (we are minting more)
        let minting_positive = new_cdp.synth_minted > cdp.synth_minted
        // Owner preserved
        let owner_preserved = new_cdp.owner == cdp.owner
        owner_signed && new_collateral_value >= required_collateral && minting_positive && owner_preserved
      }
      Burn -> {
        let owner_signed =
          list.has(self.extra_signatories, cdp.owner)
        // Must be burning (negative mint quantity for synth)
        owner_signed
      }
      Liquidate -> {
        let hr =
          health_ratio(
            cdp.ada_locked,
            cdp.synth_minted,
            oracle.price,
            oracle.exponent,
          )
        // Anyone can liquidate if health ratio below threshold
        hr < liquidation_threshold
      }
    }
  }

  mint(redeemer: Data, _policy_id: PolicyId, self: Transaction) -> Bool {
    expect action: Action = redeemer
    when action is {
      Mint -> {
        // A CDP script input must be spent in the same transaction
        script_input_exists(self.inputs, cdp_script_hash)
      }
      Burn -> {
        // A CDP script input must be spent for burn as well
        script_input_exists(self.inputs, cdp_script_hash)
      }
      Liquidate -> {
        // Liquidation burns synth tokens; CDP input required
        script_input_exists(self.inputs, cdp_script_hash)
      }
    }
  }
}

